  }))), "\uC544\uB798 \uB0B4\uC6A9\uB9CC \uBD10\uB3C4 1\uBD80\uC758 \uB0B4\uC6A9\uC744 \uC694\uC545\uD560 \uC218 \uC788\uB2E4."), mdx("div", {
    "className": "gatsby-highlight",
